import { useEffect, useState, useCallback, useRef } from 'react';
import axios from 'axios';
import {
  LineChart, Line, ResponsiveContainer, Tooltip as ReTooltip, AreaChart, Area,
  XAxis, YAxis, CartesianGrid, Legend,
} from 'recharts';

const API = process.env.REACT_APP_API_URL || 'http://localhost:8000';

/* ─────────────────────── helpers ─────────────────────── */
const fmtTime = (iso) => {
  if (!iso) return '—';
  return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
};
const fmtDate = (iso) => {
  if (!iso) return '—';
  return new Date(iso).toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
};
const timeAgo = (iso) => {
  if (!iso) return '—';
  const diff = (Date.now() - new Date(iso).getTime()) / 1000;
  if (diff < 60) return `${Math.round(diff)}s ago`;
  if (diff < 3600) return `${Math.round(diff / 60)}m ago`;
  return `${Math.round(diff / 3600)}h ago`;
};

const severityColor = (s) => {
  if (!s) return '#4ade80';
  const m = { Critical: '#ff4757', High: '#ff6b35', Medium: '#ffb347', Low: '#f7e25a', Normal: '#4ade80' };
  return m[s] || '#4ade80';
};
const nodeStatusColor = (node) => {
  if (node.active_anomalies > 0) {
    const sev = node.latest_anomaly?.severity;
    return severityColor(sev);
  }
  if (node.status === 'critical') return '#ff4757';
  if (node.status === 'warning') return '#ffb347';
  if (node.status === 'online') return '#4ade80';
  return '#6c757d';
};

const cpuValue = (node) => {
  const m = node.latest_metrics?.find(x => x.metric_name === 'cpu_usage_percent');
  return m ? m.value : null;
};
const memValue = (node) => {
  const m = node.latest_metrics?.find(x => x.metric_name === 'memory_usage_percent');
  return m ? m.value : null;
};
const netValue = (node) => {
  const m = node.latest_metrics?.find(x => x.metric_name === 'network_rx_mbps');
  return m ? m.value : null;
};

/* ─────────────────────── Sparkline ─────────────────────── */
function Sparkline({ data = [], color = '#00d4ff', label }) {
  if (!data.length) return <div style={{ height: 38, display: 'flex', alignItems: 'center', color: '#444', fontSize: 11 }}>No data</div>;
  const pts = data.slice(-20).map((d, i) => ({ i, v: d.value }));
  return (
    <div>
      <div style={{ fontSize: 10, color: '#aaa', marginBottom: 2 }}>{label}</div>
      <ResponsiveContainer width="100%" height={38}>
        <AreaChart data={pts} margin={{ top: 2, right: 0, left: 0, bottom: 2 }}>
          <defs>
            <linearGradient id={`sg-${color.replace('#', '')}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor={color} stopOpacity={0.3} />
              <stop offset="95%" stopColor={color} stopOpacity={0} />
            </linearGradient>
          </defs>
          <Area type="monotone" dataKey="v" stroke={color} strokeWidth={1.5}
            fill={`url(#sg-${color.replace('#', '')})`} dot={false} isAnimationActive={false} />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

/* ─────────────────────── Stat Pill ─────────────────────── */
function StatPill({ label, value, color = '#00d4ff', icon }) {
  return (
    <div style={{
      background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)',
      borderRadius: 12, padding: '10px 18px', minWidth: 110, flex: '1 1 110px',
      display: 'flex', flexDirection: 'column', gap: 4,
      backdropFilter: 'blur(8px)',
    }}>
      <div style={{ fontSize: 11, color: '#888', letterSpacing: 1, textTransform: 'uppercase' }}>
        {icon} {label}
      </div>
      <div style={{ fontSize: 24, fontWeight: 700, color, lineHeight: 1 }}>{value ?? '—'}</div>
    </div>
  );
}

/* ─────────────────────── Node Card ─────────────────────── */
function NodeCard({ node, onClick }) {
  const border = nodeStatusColor(node);
  const hasAnomaly = node.active_anomalies > 0;
  const cpu = cpuValue(node);
  const mem = memValue(node);
  const net = netValue(node);

  return (
    <div
      onClick={() => onClick(node)}
      style={{
        position: 'relative', cursor: 'pointer',
        background: 'rgba(255,255,255,0.04)',
        border: `1.5px solid ${border}40`,
        borderLeft: `3px solid ${border}`,
        borderRadius: 14,
        padding: '14px 16px',
        backdropFilter: 'blur(12px)',
        transition: 'transform 0.18s ease, box-shadow 0.18s ease',
        boxShadow: hasAnomaly ? `0 0 18px ${border}30, 0 2px 12px rgba(0,0,0,0.4)` : '0 2px 12px rgba(0,0,0,0.35)',
        overflow: 'hidden',
      }}
      onMouseEnter={e => {
        e.currentTarget.style.transform = 'translateY(-3px)';
        e.currentTarget.style.boxShadow = `0 8px 28px ${border}40, 0 4px 16px rgba(0,0,0,0.5)`;
      }}
      onMouseLeave={e => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = hasAnomaly ? `0 0 18px ${border}30, 0 2px 12px rgba(0,0,0,0.4)` : '0 2px 12px rgba(0,0,0,0.35)';
      }}
    >
      {/* Anomaly pulse ring */}
      {hasAnomaly && (
        <span style={{
          position: 'absolute', top: 10, right: 10,
          width: 10, height: 10, borderRadius: '50%',
          background: border, boxShadow: `0 0 0 0 ${border}`,
          animation: 'pulse 1.6s ease-out infinite',
        }} />
      )}

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
        <div>
          <div style={{ fontWeight: 700, fontSize: 13, color: '#e8eaf0', letterSpacing: 0.3 }}>
            {node.hostname}
          </div>
          <div style={{ fontSize: 11, color: '#666', marginTop: 1 }}>{node.ip_address || '—'}</div>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4 }}>
          <div style={{
            fontSize: 10, fontWeight: 600, padding: '2px 8px', borderRadius: 99,
            background: `${border}22`, color: border, letterSpacing: 0.5,
            textTransform: 'uppercase',
          }}>
            {node.status || 'unknown'}
          </div>
          {node.active_users > 0 && (
            <div style={{ fontSize: 10, color: '#9b8fff', display: 'flex', alignItems: 'center', gap: 4 }}>
              👤 {node.active_users} user{node.active_users > 1 ? 's' : ''}
            </div>
          )}
        </div>
      </div>

      {/* Metric values row */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 10 }}>
        {cpu !== null && (
          <div style={{ fontSize: 11 }}>
            <span style={{ color: '#888' }}>CPU </span>
            <span style={{ color: cpu > 80 ? '#ff4757' : cpu > 60 ? '#ffb347' : '#4ade80', fontWeight: 700 }}>
              {cpu.toFixed(1)}%
            </span>
          </div>
        )}
        {mem !== null && (
          <div style={{ fontSize: 11 }}>
            <span style={{ color: '#888' }}>MEM </span>
            <span style={{ color: mem > 85 ? '#ff4757' : mem > 70 ? '#ffb347' : '#4ade80', fontWeight: 700 }}>
              {mem.toFixed(1)}%
            </span>
          </div>
        )}
        {net !== null && (
          <div style={{ fontSize: 11 }}>
            <span style={{ color: '#888' }}>NET </span>
            <span style={{ color: '#00d4ff', fontWeight: 700 }}>{net.toFixed(1)} MB/s</span>
          </div>
        )}
      </div>

      {/* Sparklines */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <Sparkline data={node.sparklines?.cpu_usage_percent} color="#00d4ff" label="CPU %" />
        <Sparkline data={node.sparklines?.memory_usage_percent} color="#9b8fff" label="MEM %" />
      </div>

      {/* Anomaly badge */}
      {hasAnomaly && (
        <div style={{
          marginTop: 10, padding: '5px 10px', borderRadius: 8,
          background: `${border}15`, border: `1px solid ${border}40`,
          fontSize: 10, color: border, lineHeight: 1.4,
        }}>
          🚨 <strong>{node.active_anomalies} anomal{node.active_anomalies > 1 ? 'ies' : 'y'}</strong>
          {node.latest_anomaly?.severity && ` — ${node.latest_anomaly.severity}`}
          {node.latest_anomaly?.description && (
            <div style={{ marginTop: 2, color: '#bbb', fontSize: 9 }} title={node.latest_anomaly.description}>
              {node.latest_anomaly.description.slice(0, 60)}…
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/* ─────────────────────── Anomaly Feed ─────────────────────── */
function AnomalyFeed({ feed }) {
  return (
    <div style={{
      background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)',
      borderRadius: 16, padding: '16px', backdropFilter: 'blur(10px)',
      display: 'flex', flexDirection: 'column', gap: 0, maxHeight: '100%', overflow: 'hidden',
    }}>
      <div style={{ fontWeight: 700, fontSize: 13, color: '#e8eaf0', marginBottom: 12, letterSpacing: 0.5 }}>
        🔔 Live Anomaly Feed
      </div>
      <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 8 }}>
        {feed.length === 0 && (
          <div style={{ color: '#4ade80', fontSize: 12, padding: 8 }}>✅ No active anomalies</div>
        )}
        {feed.map((ev) => {
          const sc = severityColor(ev.severity);
          return (
            <div key={ev.id} style={{
              padding: '8px 10px', borderRadius: 10,
              background: `${sc}08`, borderLeft: `2px solid ${sc}`,
              fontSize: 11, lineHeight: 1.5,
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 2 }}>
                <span style={{ fontWeight: 700, color: sc }}>{ev.severity}</span>
                <span style={{ color: '#555', fontSize: 10 }}>{timeAgo(ev.detected_at)}</span>
              </div>
              <div style={{ color: '#bbb', fontWeight: 600 }}>{ev.hostname}</div>
              <div style={{ color: '#888' }}>{ev.metric_name?.replace(/_/g, ' ')}</div>
              <div style={{ color: '#666', fontSize: 10 }}>{ev.description?.slice(0, 70)}</div>
            </div>
          );
        })}
      </div>
    </div>
