}

/* ─────────────────────── Node Drilldown Modal ─────────────────────── */
function DrilldownModal({ node, onClose }) {
  const [anomalies, setAnomalies] = useState([]);
  const [users, setUsers] = useState([]);
  const [processes, setProcesses] = useState([]);
  const [metrics, setMetrics] = useState([]);
  const [tab, setTab] = useState('overview');

  useEffect(() => {
    if (!node) return;
    const id = node.id;
    axios.get(`${API}/api/cluster/node/${id}/anomalies?limit=30`).then(r => setAnomalies(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/node/${id}/users`).then(r => setUsers(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/node/${id}/processes`).then(r => setProcesses(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/node/${id}/metrics?limit=120`).then(r => setMetrics(r.data)).catch(() => {});
  }, [node]);

  if (!node) return null;

  // Build chart data by metric name
  const buildChart = (metricName) => {
    return metrics
      .filter(m => m.metric_name === metricName)
      .slice(0, 60)
      .reverse()
      .map((m, i) => ({ i, value: parseFloat(m.value.toFixed(2)), time: fmtTime(m.timestamp) }));
  };

  const chartMetrics = [...new Set(metrics.map(m => m.metric_name))];
  const metricColors = ['#00d4ff', '#9b8fff', '#4ade80', '#ffb347', '#ff6b35'];

  const tabs = ['overview', 'metrics', 'anomalies', 'users', 'processes'];

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 1000,
      background: 'rgba(0,0,0,0.75)', backdropFilter: 'blur(6px)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      padding: 24,
    }} onClick={onClose}>
      <div style={{
        background: '#0d1117', border: '1px solid rgba(255,255,255,0.1)',
        borderRadius: 20, width: '100%', maxWidth: 860,
        maxHeight: '90vh', overflow: 'hidden',
        display: 'flex', flexDirection: 'column',
        boxShadow: '0 24px 80px rgba(0,0,0,0.8)',
      }} onClick={e => e.stopPropagation()}>

        {/* Modal Header */}
        <div style={{
          padding: '20px 24px', borderBottom: '1px solid rgba(255,255,255,0.06)',
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          background: 'rgba(0,212,255,0.04)',
        }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 800, color: '#e8eaf0', letterSpacing: 0.5 }}>
              🖥️ {node.hostname}
            </div>
            <div style={{ fontSize: 12, color: '#888', marginTop: 2 }}>
              {node.ip_address} · {node.os_version || 'Linux'} · {node.architecture || 'x86_64'}
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{
              padding: '4px 12px', borderRadius: 99, fontSize: 11, fontWeight: 700,
              background: `${nodeStatusColor(node)}22`, color: nodeStatusColor(node),
              textTransform: 'uppercase', letterSpacing: 0.5,
            }}>
              {node.status || 'unknown'}
            </div>
            <button onClick={onClose} style={{
              background: 'rgba(255,255,255,0.07)', border: '1px solid rgba(255,255,255,0.1)',
              color: '#aaa', borderRadius: 8, padding: '6px 14px', cursor: 'pointer', fontSize: 13,
            }}>✕ Close</button>
          </div>
        </div>

        {/* Tab bar */}
        <div style={{
          display: 'flex', borderBottom: '1px solid rgba(255,255,255,0.06)',
          padding: '0 24px',
        }}>
          {tabs.map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              background: 'none', border: 'none', cursor: 'pointer',
              padding: '12px 16px', fontSize: 12, fontWeight: 600,
